  const scenario = {
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        kind: "quote" as const,
        items: [{ kind: "potion" as const }],
      },
    ],
  };
  expect(processScenario(scenario)).toEqual({
    results: [{ kind: "quote", premium: 49 }],
  });
});

